import { isVertical } from './orientation.js';
import type { Orientation } from '../../../../../core/types/orientation.js';
import { Dimensions } from '../../../types/dimensions.js';
import { sanitizeLegendRatio } from '../../../utils/sanitize-legend-ratio.js';

export const calculateLegendSizeBasedOnRatio = (
  orientation: Orientation,
  containerWidth: number,
  containerHeight: number,
  ratio: number,
): Dimensions => {
  const sanitizedRatio = sanitizeLegendRatio(ratio);

  const fraction = sanitizedRatio * 0.01;

  const width = isVertical(orientation)
    ? containerWidth
    : fraction * containerWidth;
  const height = !isVertical(orientation)
    ? containerHeight
    : fraction * containerHeight;

  return { width, height };
};
